import type { Ledger } from "../ledger/ledger.ts";
import { transactionBoundaryFor, type RefundReceipt, type TransactionBoundary } from "../transactions/transaction-boundary.ts";

export type RefundSucceeded = {
  id: string;
  type: "refund.succeeded";
  customerId: string;
